  // Real-time Reels sync with Firestore database
  useEffect(() => {
    const q = query(collection(db, "reels"), orderBy("createdAt", "desc"));
    const unsubscribe = onSnapshot(q, (snapshot) => {
      const firestoreReels = snapshot.docs.map(doc => {
        const data = doc.data();
        let rawUrl = data.videoUrl || data.publicUrl || data.mediaUrl || "";
        let finalUrl = "";
        
        if (data.objectKey) {
          // Reconstruct using public CDN domain and objectKey
          finalUrl = `https://media.sehrlive.soulverseapps.com/${data.objectKey}`;
        } else {
          finalUrl = normalizeReelUrl(rawUrl);
        }

        return {
          id: doc.id,
          creator: data.creator || "Anonymous Creator",
          avatar: data.avatar || "https://images.unsplash.com/photo-1535713875002-d1d0cf377fde?auto=format&fit=crop&w=150&h=150&q=80",
          caption: data.caption || "",
          song: data.song || "Original Sound",
          videoBg: data.videoBg || "bg-gradient-to-tr from-[#ff007f] via-[#12121a] to-[#7b2cbf]",
          videoUrl: finalUrl,
          likes: data.likes || 0,
          commentsCount: data.commentsCount || 0,
          liked: data.liked || false,
          privacy: data.privacy || "public",
          location: data.location || "Lahore, Pakistan",
          saves: data.saves || 0,
          saved: data.saved || false,
          shares: data.shares || 0,
          downloads: data.downloads || 0,
          isFollowed: data.isFollowed || false,
          comments: data.comments || [],
          uploaderId: data.uploaderId || "",
          createdAt: data.createdAt || ""
        };
      });
      
      if (firestoreReels.length > 0) {
        setReels(prev => {
          // Filter out private reels from the main public feed
          const publicFirestoreReels = firestoreReels.filter(r => r && r.privacy !== "private");
          const staticReels = prev.filter(r => r && r.id && typeof r.id === "string" && (r.id.startsWith("r") || !publicFirestoreReels.some(fr => fr && fr.id === r.id)));
          return [...publicFirestoreReels, ...staticReels];
        });

        // Sync profileReels dynamically from Firestore as well!
        const myReels = firestoreReels.filter(r => r.uploaderId === user.uniqueId || (r.uploaderId === "" && r.creator === (user.fullName || "Syed Prince Shah")));
        
        const myUploaded = myReels.filter(r => r.privacy !== "private").map(r => ({
          id: r.id,
          title: r.caption ? (r.caption.split(" ").slice(0, 4).join(" ") + "...") : "My Clip 🎬",
          views: "1.2K",
          likes: r.likes,
          liked: r.liked,
          videoBg: r.videoBg,
          videoUrl: r.videoUrl,
          caption: r.caption,
          song: r.song,
          comments: r.comments.map((c: any) => typeof c === 'string' ? c : (c.text || "")),
          duration: "0:30",
          location: r.location,
          isPrivate: false,
          privacy: "public",
          saves: r.saves,
          shares: r.shares,
          downloads: r.downloads,
          creator: r.creator,
          avatar: r.avatar
        }));

        const myPrivate = myReels.filter(r => r.privacy === "private").map(r => ({
          id: r.id,
          title: r.caption ? (r.caption.split(" ").slice(0, 4).join(" ") + "...") : "My Private Clip 🔒",
          views: "Host Private",
          likes: r.likes,
          liked: r.liked,
          videoBg: r.videoBg,
          videoUrl: r.videoUrl,
          caption: r.caption,
          song: r.song,
          comments: r.comments.map((c: any) => typeof c === 'string' ? c : (c.text || "")),
          duration: "0:30",
          location: r.location,
          isPrivate: true,
          privacy: "private",
          saves: r.saves,
          shares: r.shares,
          downloads: r.downloads,
          creator: r.creator,
          avatar: r.avatar
        }));

        setProfileReels(prev => {
          const nonDbUploaded = prev.uploaded.filter(r => r && r.id && typeof r.id === "string" && r.id.startsWith("u") && !myUploaded.some(mu => mu && mu.id === r.id));
          const nonDbPrivate = prev.private.filter(r => r && r.id && typeof r.id === "string" && r.id.startsWith("p") && !myPrivate.some(mp => mp && mp.id === r.id));
          return {
            ...prev,
            uploaded: [...myUploaded, ...nonDbUploaded],
            private: [...myPrivate, ...nonDbPrivate]
          };
        });
      }
    }, (error) => {
      console.error("Firestore reels subscription error:", error);
    });
    return () => unsubscribe();
  }, [user.uniqueId, user.fullName]);

