  // Send Chat Message with optional AI Moderation/Translation
  const handleSendChatMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (commentsDisabled) {
      alert("🔒 Room Comments have been turned off in this live room by the host.");
      return;
    }
    if (!chatInput.trim()) return;

    const messageText = chatInput.trim();
    setChatInput("");

    // Create message locally first
    const timestamp = new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    const localId = Date.now().toString();

    let finalMsg: ChatMessage = {
      id: localId,
      username: user.username,
      message: messageText,
      vipLevel: user.vipLevel,
      userLevel: user.userLevel,
      badge: "Family Leader 👑",
      isSystem: false,
      isFlagged: false,
      timestamp
    };

    // Append user message immediately
    setChatMessages(prev => [...prev, finalMsg]);
    updateMissionProgress("m-3", 1);

    // Call Real-time AI server endpoints if toggled
    if (isAiMode) {
      setIsModerating(true);
      setIsTranslating(true);

      try {
        // Parallelized Server API Requests
        const [modRes, transRes] = await Promise.all([
          fetch("/api/ai/moderate", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ text: messageText })
          }).then(r => r.json()),
          fetch("/api/ai/translate", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ text: messageText, targetLanguage: targetTranslateLang })
          }).then(r => r.json())
        ]);

        setIsModerating(false);
        setIsTranslating(false);

        // Process AI Moderation results
        if (modRes.flagged) {
          // Flag message as offensive in client UI & admin console
          setChatMessages(prev =>
            prev.map(m =>
              m.id === localId
                ? {
                    ...m,
                    isFlagged: true,
                    message: `⚠️ [REDACTED BY AI MODERATION]`,
                    flagReason: modRes.reason
                  }
                : m
            )
          );

          // Add to admin log alerts
          setModerationLogs(prev => [
            {
              id: Date.now().toString(),
              user: user.username,
              text: messageText,
              flag: `AI: ${modRes.reason}`,
              action: "Restricted View"
            },
            ...prev
          ]);
        } else {
          // Append translation successfully
          if (transRes.translatedText && transRes.translatedText !== messageText) {
            setChatMessages(prev =>
              prev.map(m =>
                m.id === localId
                  ? { ...m, translated: transRes.translatedText }
                  : m
              )
            );
          }
        }

        // Trigger AI Host Vocal/Verbal response if not flagged!
        if (!modRes.flagged) {
          setIsGeneratingHostReply(true);
          const hostReplyRes = await fetch("/api/ai/host-response", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
              hostName: activeHost.name,
              hostRole: activeHost.role,
              userMessage: messageText,
              lastAction: "chat"
            })
          }).then(r => r.json());

          setIsGeneratingHostReply(false);

          // Add simulated host message to chat
          setChatMessages(prev => [
            ...prev,
            {
              id: Date.now().toString(),
              username: activeHost.name,
              message: hostReplyRes.reply,
              vipLevel: 0,
              userLevel: 99,
              badge: "HOST 🎙️",
              isSystem: false,
              isFlagged: false,
              timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
            }
          ]);
        }

      } catch (err) {
        console.error("AI Server calls failed", err);
        setIsModerating(false);
        setIsTranslating(false);
        setIsGeneratingHostReply(false);
      }
    }
  };

  // Send Direct Message (Private Chat View via real-time Firestore)
  const handleSendDirectMessage = async (
    e?: React.FormEvent,
    isSticker = false,
    stickerChar = "",
    isVoice = false,
    voiceDuration = 0,
    isImage = false,
    imageUrl = "",
    customTextOverride = ""
  ) => {
    if (e) e.preventDefault();
    
    const otherUsername = activeChatContact?.username || activeChatContact?.name;
    if (!otherUsername || !user?.username) {
      console.warn("[SEHR-LIVE CHAT] Cannot send DM: Active contact or logged-in user not identified.");
      return;
    }

    if (!directChatInput.trim() && !isSticker && !isVoice && !isImage && !customTextOverride) return;

    let text = "";
    if (isVoice) {
      text = `🎙️ Voice Message (${voiceDuration}s)`;
    } else if (isImage) {
      text = "📷 Photo Attached";
    } else if (isSticker) {
      text = stickerChar;
    } else if (customTextOverride) {
      text = customTextOverride;
    } else {
      text = directChatInput;
    }

    if (!isSticker && !isVoice && !isImage && !customTextOverride) {
      setDirectChatInput("");
    }

    const conversationId = [user.username, otherUsername].sort().join("_");
    const messageId = `msg-${Date.now()}-${Math.floor(1000 + Math.random() * 9000)}`;

    const messageData = {
      messageId,
      senderId: user.username,
      receiverId: otherUsername,
      type: isVoice ? "voice" : isImage ? "image" : isSticker ? "sticker" : "text",
      text,
      mediaUrl: isImage ? imageUrl : "",
      voiceDuration: isVoice ? voiceDuration : 0,
      createdAt: new Date().toISOString(),
      status: "sent"
    };

    try {
      const convRef = doc(db, "conversations", conversationId);
      
      // Get current unread count for the other participant
      let currentUnread = 0;
      try {
        const convSnap = await getDoc(convRef);
        if (convSnap.exists()) {
          const cData = convSnap.data();
          currentUnread = cData?.unreadCounts?.[otherUsername] || 0;
        }
      } catch (err) {
        console.error("Error reading conversation unread count:", err);
      }

      // 1. Save/Update parent conversation document
      const convData = {
        id: conversationId,
        participants: [user.username, otherUsername],
        lastMessage: text,
        lastMessageType: isVoice ? "voice" : isImage ? "image" : isSticker ? "sticker" : "text",
        lastMessageAt: new Date().toISOString(),
        lastSenderId: user.username,
        updatedAt: new Date().toISOString(),
        unreadCounts: {
          [user.username]: 0, // sender unread count is always 0
          [otherUsername]: currentUnread + 1 // increment recipient's unread count
        }
      };
      await setDoc(convRef, convData, { merge: true });

      // 2. Save individual message document in subcollection
      const msgRef = doc(db, "conversations", conversationId, "messages", messageId);
      await setDoc(msgRef, messageData);

      console.log("[SEHR-LIVE CHAT] Message synced to Firestore:", messageId);
    } catch (err) {
      console.error("Error sending message to Firestore:", err);
    }
  };

  // Gift Queue Processor
  useEffect(() => {
    if (!currentPlayingGift && giftQueue.length > 0) {
      const nextGift = giftQueue[0];
      setGiftQueue(prev => prev.slice(1));
      setCurrentPlayingGift(nextGift);
    }
  }, [currentPlayingGift, giftQueue]);

  // Gift Sending Engine
  const handleSendGift = async (gift: Gift, count: number = 1, recipientName: string = activeHost.name, isCombo: boolean = false) => {
    const totalCost = gift.cost * count;
    if (user.coins < totalCost) {
      alert(`Insufficient Coins! You need ${totalCost} coins but only have ${user.coins}.`);
      return;
    }

    const requestId = `req-gift-${Date.now()}-${Math.floor(Math.random() * 100000)}`;

    // Determine target side for PK score & earnings
    const recLower = recipientName.toLowerCase();
    const isOpponentTarget = recLower.includes("host b") || 
                             recLower.includes("opponent") ||
                             recLower.includes("alpha_queen") ||
                             recLower.includes("other") ||
                             recLower.includes("side b");

    // Deduct local balance immediately (optimistic update)
    const coinsDeducted = totalCost;
    const xpGained = Math.floor(totalCost * 0.2);

    setUser(prev => ({
      ...prev,
      coins: Math.max(0, prev.coins - coinsDeducted),
      xp: prev.xp + xpGained,
      userLevel: Math.floor((prev.xp + xpGained) / 100) + 1,
      wealthLevel: prev.wealthLevel + 1
    }));

    // Perform secure backend transaction call
    try {
      const resp = await fetch("/api/v1/gifts/send", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          requestId,
          giftId: gift.id,
          count,
          recipient: recipientName,
          targetHostSide: isOpponentTarget ? "hostB" : "hostA"
        })
      });
      if (resp.ok) {
        const data = await resp.json();
        if (data.remainingCoins !== undefined) {
          setUser(prev => ({ ...prev, coins: data.remainingCoins }));
        }
      }
    } catch (err) {
      console.error("Backend gift transaction API error:", err);
    }

    setLiveRoomTopGifters(prev => {
      const userIndex = prev.findIndex(g => g.username === user.username);
      let updated = [...prev];
      if (userIndex > -1) {
        updated[userIndex] = {
          ...updated[userIndex],
          coinsContributed: updated[userIndex].coinsContributed + totalCost
        };
      } else {
        updated.push({
          id: `u-${user.uniqueId || Date.now()}`,
          username: user.username,
          avatar: user.avatar || "https://images.unsplash.com/photo-1535713875002-d1d0cf377fde?auto=format&fit=crop&w=100&h=100&q=80",
          coinsContributed: totalCost
        });
      }
      return updated.sort((a, b) => b.coinsContributed - a.coinsContributed).slice(0, 3);
    });

    // Add transaction ledger entry
    const newTx: Transaction = {
      id: `TX-${Date.now().toString().slice(-4)}`,
      type: "gift_sent",
      amount: coinsDeducted,
      currency: "coins",
      timestamp: new Date().toISOString().replace("T", " ").slice(0, 16),
      status: "Completed",
      details: `Sent ${count}x ${gift.name} (${gift.icon}) to ${recipientName}`
    };
    setTransactions(prev => [newTx, ...prev]);

    // Save into history items
    const newHistoryItem = {
      id: `h-${Date.now()}-${Math.random()}`,
      giftName: gift.name,
      giftIcon: gift.icon,
      amount: totalCost,
      recipient: recipientName,
      date: "Today, " + new Date().toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" }),
      status: "Completed"
    };
    try {
      const savedHistory = JSON.parse(localStorage.getItem("sehr_live_history_v1") || "[]");
      localStorage.setItem("sehr_live_history_v1", JSON.stringify([newHistoryItem, ...savedHistory]));
    } catch (e) {
      console.error(e);
    }

    // Track Gift combo with full metadata for live screen display
    let newComboCount = count;
    if (activeCombo && activeCombo.giftId === gift.id) {
      newComboCount = activeCombo.count + count;
    }
    setActiveCombo({ 
      giftId: gift.id, 
      giftName: gift.name, 
      giftIcon: gift.icon, 
      count: newComboCount 
    });

    if (comboTimeoutRef.current) clearTimeout(comboTimeoutRef.current);
    comboTimeoutRef.current = setTimeout(() => {
      setActiveCombo(null);
    }, 3000);

    // Update real-time live stream gift toast overlay
    const newGiftToast = {
      id: "toast-" + Date.now() + "-" + Math.random(),
      username: user.username,
      giftName: gift.name,
      giftIcon: gift.icon,
      count: newComboCount,
      avatar: user.avatarUrl || user.avatar || "https://images.unsplash.com/photo-1535713875002-d1d0cf377fde?auto=format&fit=crop&w=100&q=80"
    };
    setUserLiveGiftToasts(prev => [newGiftToast, ...prev.slice(0, 1)]);
    setTimeout(() => {
      setUserLiveGiftToasts(prev => prev.filter(t => t.id !== newGiftToast.id));
    }, 4000);

    // If PK Battle is active: 1 Gift Coin Value = 1 PK Point!
    if (activeHost.category === "pk" || activeHost.category === "1v1") {
      if (isOpponentTarget) {
        setPkScoreOpponent(prev => prev + totalCost);
      } else {
        setPkScoreHost(prev => prev + totalCost);
      }
    }

    // Append system message to chat
    const giftSysMsg: ChatMessage = {
      id: Date.now().toString(),
      username: "System",
      message: `👑 ${user.username} sent [${gift.name} ${gift.icon} x${count}] to ${recipientName}!`,
      vipLevel: user.vipLevel,
      userLevel: user.userLevel,
      isSystem: true,
      isFlagged: false,
      timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
    };
    setChatMessages(prev => [...prev, giftSysMsg]);

    // Trigger premium global banner ("gifting ki broad patti") on all screens for big/any gift
    triggerGlobalGiftBanner(user.username, gift.name, `${gift.icon} x${count}`, recipientName);

    // Add to the Advanced Gifting Sequential Queue
    const newAnim = {
      id: `anim-${Date.now()}-${Math.random()}`,
      sender: user.username,
      recipient: recipientName,
      gift,
      comboCount: count
    };
    setGiftQueue(prev => [...prev, newAnim]);

    // Handle Legacy Luxury / 3D Full Screen Animation Effects if not playing from queue
    if (gift.type === GiftType.LUXURY || gift.type === GiftType.THREE_D) {
      setLuxuryGiftActive(gift);
      setTimeout(() => {
        setLuxuryGiftActive(null);
      }, 3500);
    }

    // Update Daily Mission
    updateMissionProgress("m-2", count);

    // Call AI Host interaction API to generate a customized thank you response!
    try {
      const response = await fetch("/api/ai/host-response", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          hostName: activeHost.name,
          hostRole: activeHost.role,
          userMessage: `Sent you ${count}x ${gift.name} (${gift.icon})!`,
          lastAction: "gift"
        })
      });
      const data = await response.json();

      // Post host reaction as a chat message
      setChatMessages(prev => [
        ...prev,
        {
          id: Date.now().toString() + "-reply",
          username: activeHost.name,
          message: data.reply,
          vipLevel: 0,
          userLevel: 99,
          badge: "HOST 🎙️",
          isSystem: false,
          isFlagged: false,
          timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
        }
      ]);
    } catch (err) {
      console.error("AI host reply fail", err);
    }
  };

