                                setSelectedPaymentPackage(null);
                                setCardFormHolder("");
                                setCardFormNumber("");
                                setCardFormExpiry("");
                                setCardFormCvv("");
                                setReportSuccessToast(`Mubarak! Successfully recharged ${selectedPaymentPackage.coins.toLocaleString()} Coins!`);
