                                        <div className="absolute top-2.5 left-2.5 bg-yellow-500/80 backdrop-blur-sm text-black px-2 py-0.5 rounded-full text-[7.5px] font-black flex items-center space-x-1 shadow z-10">
                                          <span>💎</span>
                                          <span>145.8K</span>
                                        </div>
