                                                              if (userLivePinnedCommentId === msg.id) {
                                                                setUserLivePinnedCommentId(null);
                                                                alert("📌 Comment unpinned.");
                                                              } else {
                                                                setUserLivePinnedCommentId(msg.id);
                                                                alert(`📌 Pinned @${msg.username}'s comment!`);
                                                              }
